import React, { useContext, useEffect, useState } from 'react';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import Button from '@mui/material/Button';
import Typography from '@mui/material/Typography';
import { CardActionArea, Grid, IconButton, TextField } from '@mui/material';
import { useNavigate, useParams } from 'react-router-dom';
import { ListingContext } from './contexts/ListingContext';
import { useAuthUser } from 'react-auth-kit'
import CommentDataService from './services/comment.service'
import { Delete } from '@mui/icons-material';
import { List, ListItem, ListItemAvatar, ListItemText, Avatar } from "@mui/material";
import { Check, Close } from "@mui/icons-material";
import { blue, red } from "@mui/material/colors";

export default function Comment({ body, author, _id, deleteComment }) {

    const auth = useAuthUser()
    const [isCommentAuthor, setIsCommentAuthor] = useState(false)
    const [confirmDelete, setConfirmDelete] = useState(false)

    useEffect(() => {
        { auth() && setIsCommentAuthor(auth()._id === author._id) }
    }, [])

    const handleDelete = () => {
        deleteComment(_id)
    }

    return (
        <Card sx={{ width: '100%', m: 'auto' }}>
            {confirmDelete ?
                        <Grid container direction='row' display='flex' xs={12} padding={2}>
              <List>
                  <Grid container direction='row'>
                        <ListItem button onClick={handleDelete}>
                            <ListItemAvatar>
                                <Avatar style={{ backgroundColor: blue[100], color: blue[600] }}>
                                    <Check></Check>
                                </Avatar>
                            </ListItemAvatar>
                            <ListItemText>
                                Delete
                            </ListItemText>
                        </ListItem>
                        <ListItem button onClick={()=>setConfirmDelete(false)}>
                            <ListItemAvatar>
                                <Avatar style={{ backgroundColor: red[100], color: red[600] }}>
                                    <Close></Close>
                                </Avatar>
                            </ListItemAvatar>
                            <ListItemText>
                                Cancel
                            </ListItemText>
                        </ListItem>
                        </Grid>
                    </List>              
</Grid>
:
            <Grid container direction='row' display='flex' xs={12} padding={2}>
                <Grid container item xs={11} direction='row' rowGap={1} alignItems='center'>
                    {/* <Grid item direction='column' xs={1}>
                <Avatar alt="Remy Sharp" src="https://res.cloudinary.com/deuft4auk/image/upload/v1665117910/Personal%20Website/canyon_ibikw8.jpg" />
                </Grid> */}
                <Grid item direction='column' xs={1}>
                    <Grid container item xs={12}>

                        <Typography variant="subtitle2" component='div' color="primary">
                            <b>{author.username}</b>
                        </Typography>
                    </Grid>

                    <Grid container item xs={12}>

                        <Typography variant='body2' component='div' color="text.primary">
                            {body}
                        </Typography>
                    </Grid>
                    </Grid>



                </Grid>
                {isCommentAuthor &&
                    <Grid container item xs={1} direction='column' justifyContent='center' alignItems='flex-end' borderLeft='1px solid lightgray' width='100%' >
                        <IconButton onClick={()=>setConfirmDelete(true)}>
                            <Delete fontSize='small' />
                        </IconButton>
                    </Grid>
                }
            </Grid>
}
        </Card>
    );
}

