import React, { useContext, useState } from 'react';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import Button from '@mui/material/Button';
import Typography from '@mui/material/Typography';
import { CardActionArea, Grid, TextField } from '@mui/material';
import { useNavigate, useParams } from 'react-router-dom';
import { ListingContext } from './contexts/ListingContext';
import {useAuthUser} from 'react-auth-kit'
import CommentDataService from './services/comment.service'
import ListingDataService from './services/listing.service'

export default function CommentForm() {
    const { id } = useParams()
    const {setCurrentListing, setComments} = useContext(ListingContext)

    const [comment, setComment] = useState('')
    const [focus, setFocus] = useState(false)
    const auth = useAuthUser()

    const handleCommentChange = (event) => {
        setComment(event.target.value)
    }

    const handleSubmit = async (event) => {
        event.preventDefault()
        const obj = { body: comment, id }
        setComment('')
        await CommentDataService.create(obj)
        await ListingDataService.get(id)
        .then(({ data }) => {
            console.log(data)
            setComments([...data.comments])
        })
    }

    return (
        // <Card sx={{height: 'auto', width: '100%'}} >
        //     <CardContent>
                <Grid container direction='column' width='100%'>
                <form onSubmit={handleSubmit}>
                    <Grid container item rowGap={2}>
                        {/* <Typography variant="h5" color="text.secondary">
                            Leave a comment
                        </Typography> */}
                        <TextField
                            id="outlined-username-input"
                            onFocus={() => setFocus(true)}
                            onBlur={() => setFocus(false)}
                            label="Comment"
                            type="text"
                            value={comment}
                            onChange={handleCommentChange}
                            autoComplete="new-comment"
                            size="small"
                            fullWidth
                            required
                            multiline
                            rows={focus ? 3 : 1}
                        />

                        <Button
                            type="submit"
                            color='primary'
                            variant='contained'
                            sx={{ width: '100%', mx: 'auto' }}>
                            Post
                        </Button>

                    </Grid>
                </form>
                </Grid>
    );
}

