import axios from "axios";
const loc = window.location

class UploadFilesService {
  upload(images) {
    let formData = new FormData();
    // console.log(images)
    // formData.append("images", images);
    for (let i = 0; i < images.length; i++) {
        formData.append('images', images[i].data);
      }

    // return axios.post('http://localhost:8080/data/listings/upload', formData,{
    //     headers: {
    //       "Access-Control-Allow-Origin": "http://localhost:8081",
    //       'Content-Type': 'multipart/form-data'
    //     }
    // })
    
    return axios.post(`${loc.protocol}//${loc.hostname}${loc.hostname === 'localhost' ? ':8080/data/listings/upload' : '/data/listings/upload'}`, formData,{
        headers: {
          "Access-Control-Allow-Origin": "http://localhost:8081",
          'Content-Type': 'multipart/form-data'
        }
    })
   

    // return http.post("/listings", formData)
  }

//   getFiles() {
//     return http.get("/files");
//   }
}

export default new UploadFilesService();